export interface Tag {
  en: string;
  zh: string;
}

export type ProcessingStatus = 'idle' | 'processing' | 'success' | 'error';

export interface ImageItem {
  id: string;
  file: File;
  previewUrl: string;
  status: ProcessingStatus;
  tags: Tag[];
  error?: string;
}

export interface TagResponse {
  tags: Tag[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { TagResponse } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-2.5-flash"; // Excellent for vision tasks and speed/cost balance

/**
 * Converts a File object to a Base64 string required by the API.
 */
const fileToPart = (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve({
        inlineData: {
          data: base64String,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates tags for a single image using Gemini.
 */
export const generateImageTags = async (file: File): Promise<TagResponse> => {
  try {
    const imagePart = await fileToPart(file);

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          imagePart,
          {
            text: "Analyze this image in detail. Provide a comprehensive list of descriptive tags (keywords) that describe the subject, style, artistic medium, colors, background, and specific elements. For each tag, provide the English word and its concise Chinese translation."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tags: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  en: { type: Type.STRING, description: "The tag in English" },
                  zh: { type: Type.STRING, description: "The tag in Chinese" }
                },
                required: ["en", "zh"]
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("No response from AI");
    }

    return JSON.parse(text) as TagResponse;
  } catch (error) {
    console.error("Error generating tags:", error);
    throw error;
  }
};

import JSZip from 'jszip';
import { ImageItem } from '../types';

export const generateZip = async (images: ImageItem[]): Promise<Blob> => {
  const zip = new JSZip();
  const folderName = `tagmaster_batch_${new Date().toISOString().slice(0, 10)}`;
  const root = zip.folder(folderName);

  if (!root) throw new Error("Failed to create zip folder");

  for (const img of images) {
    // Add the image file
    root.file(img.file.name, img.file);

    // Format tags: en1, en2, en3...
    // You can customize this format (e.g., Danbooru style)
    const tagContent = img.tags.map(t => t.en).join(', ');

    // Create a text file with the same name as the image
    const txtFileName = img.file.name.replace(/\.[^/.]+$/, "") + ".txt";
    root.file(txtFileName, tagContent);
  }

  return await zip.generateAsync({ type: "blob" });
};

export const downloadBlob = (blob: Blob, filename: string) => {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

