import React, { useRef, useCallback } from 'react';
import { UploadCloud, Image as ImageIcon } from 'lucide-react';

interface UploadAreaProps {
  onUpload: (files: File[]) => void;
  isProcessing: boolean;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload, isProcessing }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFiles = useCallback((files: FileList | null) => {
    if (!files) return;
    const validFiles = Array.from(files).filter(file => file.type.startsWith('image/'));
    if (validFiles.length > 0) {
      onUpload(validFiles);
    }
  }, [onUpload]);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (isProcessing) return;
    handleFiles(e.dataTransfer.files);
  };

  const handleClick = () => {
    if (!isProcessing && fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  return (
    <div
      onDragOver={(e) => e.preventDefault()}
      onDrop={handleDrop}
      onClick={handleClick}
      className={`
        border-2 border-dashed rounded-xl p-10 text-center cursor-pointer transition-all duration-200
        ${isProcessing 
          ? 'bg-gray-50 border-gray-300 cursor-not-allowed opacity-60' 
          : 'bg-white border-indigo-200 hover:border-indigo-500 hover:bg-indigo-50 hover:shadow-sm'
        }
      `}
    >
      <input
        type="file"
        ref={fileInputRef}
        className="hidden"
        multiple
        accept="image/*"
        onChange={(e) => handleFiles(e.target.files)}
        disabled={isProcessing}
      />

      <div className="flex flex-col items-center gap-4">
        <div className={`p-4 rounded-full ${isProcessing ? 'bg-gray-200' : 'bg-indigo-100'}`}>
          <UploadCloud className={`w-8 h-8 ${isProcessing ? 'text-gray-400' : 'text-indigo-600'}`} />
        </div>
        <div>
          <h3 className="text-lg font-semibold text-gray-900">
            {isProcessing ? 'Processing Images...' : 'Drop images here or click to upload'}
          </h3>
          <p className="text-gray-500 mt-1">Supports JPG, PNG, WEBP</p>
        </div>
        {!isProcessing && (
          <div className="flex gap-4 mt-2">
            <div className="flex items-center text-xs text-gray-400 bg-gray-50 px-3 py-1 rounded-md border border-gray-100">
              <ImageIcon className="w-3 h-3 mr-1" />
              Batch Support
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

