export default ImageCard;

import React, { useState, useCallback } from 'react';
import Header from './components/Header';
import UploadArea from './components/UploadArea';
import ImageCard from './components/ImageCard';
import { ImageItem, Tag } from './types';
import { generateImageTags } from './services/geminiService';
import { generateZip, downloadBlob } from './utils/fileUtils';
import { Download, Play, Trash, AlertCircle } from 'lucide-react';
import { nanoid } from 'nanoid';

const App: React.FC = () => {
  const [images, setImages] = useState<ImageItem[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  const handleUpload = (files: File[]) => {
    const newImages: ImageItem[] = files.map(file => ({
      id: nanoid(),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'idle',
      tags: []
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const removeImage = (id: string) => {
    setImages(prev => {
      const target = prev.find(img => img.id === id);
      if (target) {
        URL.revokeObjectURL(target.previewUrl);
      }
      return prev.filter(img => img.id !== id);
    });
  };

  const clearAll = () => {
    if (window.confirm("Are you sure you want to clear all images?")) {
      images.forEach(img => URL.revokeObjectURL(img.previewUrl));
      setImages([]);
    }
  };

  const updateTags = (id: string, newTags: Tag[]) => {
    setImages(prev => prev.map(img => img.id === id ? { ...img, tags: newTags } : img));
  };

  const processQueue = useCallback(async () => {
    setIsProcessing(true);

    // We process sequentially or with limited concurrency to be safe with rate limits
    // Creating a copy of the list to iterate, but reading state for latest status
    const idsToProcess = images.filter(img => img.status === 'idle' || img.status === 'error').map(img => img.id);

    for (const id of idsToProcess) {
       // Check if we should stop (could add a stop ref later)

       // Update status to processing
       setImages(prev => prev.map(img => img.id === id ? { ...img, status: 'processing', error: undefined } : img));

       // Find current image data
       const currentImg = images.find(img => img.id === id);
       if (!currentImg) continue; // Should not happen

       try {
         const result = await generateImageTags(currentImg.file);
         setImages(prev => prev.map(img => 
           img.id === id ? { ...img, status: 'success', tags: result.tags } : img
         ));
       } catch (err: any) {
         setImages(prev => prev.map(img => 
           img.id === id ? { ...img, status: 'error', error: err.message || "Failed" } : img
         ));
       }
    }

    setIsProcessing(false);
  }, [images]);

  const handleDownloadZip = async () => {
    if (images.length === 0) return;
    setIsZipping(true);
    try {
      const blob = await generateZip(images);
      downloadBlob(blob, `tagmaster_batch_${Date.now()}.zip`);
    } catch (error) {
      console.error("Zip failed", error);
      alert("Failed to create zip file");
    } finally {
      setIsZipping(false);
    }
  };

  const stats = {
    total: images.length,
    processed: images.filter(i => i.status === 'success').length,
    pending: images.filter(i => i.status === 'idle').length,
    errors: images.filter(i => i.status === 'error').length
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full">

        {/* Top Controls */}
        <div className="space-y-6 mb-8">
          <UploadArea onUpload={handleUpload} isProcessing={isProcessing} />

          {images.length > 0 && (
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 flex flex-wrap gap-4 items-center justify-between sticky top-20 z-10">
              <div className="flex items-center gap-4 text-sm text-gray-600">
                <span className="font-semibold text-gray-900">Queue Status:</span>
                <span>Total: {stats.total}</span>
                <span className="text-green-600">Done: {stats.processed}</span>
                <span className="text-orange-500">Pending: {stats.pending}</span>
                {stats.errors > 0 && <span className="text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3"/> Errors: {stats.errors}</span>}
              </div>

              <div className="flex items-center gap-3">
                 <button
                  onClick={clearAll}
                  disabled={isProcessing}
                  className="px-4 py-2 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 disabled:opacity-50"
                >
                  <Trash className="w-4 h-4" /> Clear
                </button>

                <button
                  onClick={processQueue}
                  disabled={isProcessing || stats.pending + stats.errors === 0}
                  className={`
                    px-5 py-2 rounded-lg text-white font-medium shadow-sm transition-all flex items-center gap-2
                    ${isProcessing 
                      ? 'bg-gray-400 cursor-not-allowed' 
                      : (stats.pending + stats.errors === 0 ? 'bg-gray-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-md')
                    }
                  `}
                >
                  <Play className={`w-4 h-4 ${isProcessing ? 'animate-pulse' : 'fill-current'}`} />
                  {isProcessing ? 'Processing...' : 'Start Labeling'}
                </button>

                <button
                  onClick={handleDownloadZip}
                  disabled={isZipping || images.length === 0}
                  className="px-5 py-2 bg-gray-900 text-white rounded-lg font-medium hover:bg-gray-800 hover:shadow-md transition-all flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                   {isZipping ? (
                     <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                   ) : (
                     <Download className="w-4 h-4" />
                   )}
                   Download All
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Image Grid */}
        {images.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {images.map(img => (
              <div key={img.id} className="h-[420px]">
                <ImageCard 
                  item={img} 
                  onRemove={removeImage} 
                  onUpdateTags={updateTags}
                  onRetry={() => {
                    // Reset status to idle so the queue picks it up
                    setImages(prev => prev.map(i => i.id === img.id ? { ...i, status: 'idle', error: undefined } : i));
                  }}
                />
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-20 opacity-50">
            <p className="text-gray-400">No images added yet.</p>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { X, RefreshCw, Copy, Check, Edit2, Plus, Trash2, GripVertical } from 'lucide-react';
import { ImageItem, Tag } from '../types';

interface ImageCardProps {
  item: ImageItem;
  onRemove: (id: string) => void;
  onUpdateTags: (id: string, newTags: Tag[]) => void;
  onRetry: (id: string) => void;
}

const ImageCard: React.FC<ImageCardProps> = ({ item, onRemove, onUpdateTags, onRetry }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [newTagEn, setNewTagEn] = useState('');
  const [newTagZh, setNewTagZh] = useState('');
  const [copied, setCopied] = useState(false);
  const [draggedTagIndex, setDraggedTagIndex] = useState<number | null>(null);

  const copyTags = () => {
    const text = item.tags.map(t => t.en).join(', ');
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const removeTag = (indexToRemove: number) => {
    const updated = item.tags.filter((_, idx) => idx !== indexToRemove);
    onUpdateTags(item.id, updated);
  };

  const addTag = () => {
    if (newTagEn.trim()) {
      onUpdateTags(item.id, [...item.tags, { en: newTagEn.trim(), zh: newTagZh.trim() || 'Custom' }]);
      setNewTagEn('');
      setNewTagZh('');
    }
  };

  const updateTag = (index: number, key: 'en' | 'zh', value: string) => {
    const updated = [...item.tags];
    updated[index] = { ...updated[index], [key]: value };
    onUpdateTags(item.id, updated);
  };

  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedTagIndex(index);
    e.dataTransfer.effectAllowed = "move";
    // Required for Firefox to allow dragging
    e.dataTransfer.setData("text/plain", index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedTagIndex === null || draggedTagIndex === targetIndex) return;

    const newTags = [...item.tags];
    const [draggedItem] = newTags.splice(draggedTagIndex, 1);
    newTags.splice(targetIndex, 0, draggedItem);

    onUpdateTags(item.id, newTags);
    setDraggedTagIndex(null);
  };

  const handleDragEnd = () => {
    setDraggedTagIndex(null);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col h-full hover:shadow-md transition-shadow">
      {/* Image Preview Header */}
      <div className="relative group h-48 bg-gray-100 flex items-center justify-center overflow-hidden">
        <img 
          src={item.previewUrl} 
