import React, { useState, useCallback } from 'react';
import Header from './components/Header';
import UploadArea from './components/UploadArea';
import ImageCard from './components/ImageCard';
import { ImageItem, Tag } from './types';
import { generateImageTags } from './services/geminiService';
import { generateZip, downloadBlob } from './utils/fileUtils';
import { Download, Play, Trash, AlertCircle, Plus, Tag as TagIcon } from 'lucide-react';
import { nanoid } from 'nanoid';

const App: React.FC = () => {
  const [images, setImages] = useState<ImageItem[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);

  // Batch tag inputs
  const [batchTagEn, setBatchTagEn] = useState('');
  const [batchTagZh, setBatchTagZh] = useState('');

  const handleUpload = (files: File[]) => {
    const newImages: ImageItem[] = files.map(file => ({
      id: nanoid(),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'idle',
      tags: []
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const removeImage = (id: string) => {
    setImages(prev => {
      const target = prev.find(img => img.id === id);
      if (target) {
        URL.revokeObjectURL(target.previewUrl);
      }
      return prev.filter(img => img.id !== id);
    });
  };

  const clearAll = () => {
    if (window.confirm("Are you sure you want to clear all images?")) {
      images.forEach(img => URL.revokeObjectURL(img.previewUrl));
      setImages([]);
    }
  };

  const updateTags = (id: string, newTags: Tag[]) => {
    setImages(prev => prev.map(img => img.id === id ? { ...img, tags: newTags } : img));
  };

  const handleBatchAddTag = () => {
    if (!batchTagEn.trim()) return;

    const newTag: Tag = {
      en: batchTagEn.trim(),
      zh: batchTagZh.trim() || batchTagEn.trim()
    };

    setImages(prev => prev.map(img => ({
      ...img,
      // Add to the beginning of the array
      tags: [newTag, ...img.tags]
    })));

    setBatchTagEn('');
    setBatchTagZh('');
  };

  const processQueue = useCallback(async () => {
    setIsProcessing(true);

    const idsToProcess = images.filter(img => img.status === 'idle' || img.status === 'error').map(img => img.id);

    for (const id of idsToProcess) {
       setImages(prev => prev.map(img => img.id === id ? { ...img, status: 'processing', error: undefined } : img));

       const currentImg = images.find(img => img.id === id);
       if (!currentImg) continue;

       try {
         const result = await generateImageTags(currentImg.file);
         setImages(prev => prev.map(img => 
           img.id === id ? { ...img, status: 'success', tags: result.tags } : img
         ));
       } catch (err: any) {
         setImages(prev => prev.map(img => 
           img.id === id ? { ...img, status: 'error', error: err.message || "Failed" } : img
         ));
       }
    }

    setIsProcessing(false);
  }, [images]);

  const handleDownloadZip = async () => {
    if (images.length === 0) return;
    setIsZipping(true);
    try {
      const blob = await generateZip(images);
      downloadBlob(blob, `tagmaster_batch_${Date.now()}.zip`);
    } catch (error) {
      console.error("Zip failed", error);
      alert("Failed to create zip file");
    } finally {
      setIsZipping(false);
    }
  };

  const stats = {
    total: images.length,
    processed: images.filter(i => i.status === 'success').length,
    pending: images.filter(i => i.status === 'idle').length,
    errors: images.filter(i => i.status === 'error').length
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full">

        {/* Top Controls */}
        <div className="space-y-6 mb-8">
          <UploadArea onUpload={handleUpload} isProcessing={isProcessing} />

          {images.length > 0 && (
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 sticky top-20 z-10 flex flex-col gap-4">

              {/* Batch Actions Section */}
              <div className="flex flex-wrap items-center justify-between gap-4 pb-4 border-b border-gray-100">
                  <div className="flex items-center gap-2">
                       <div className="p-2 bg-indigo-50 rounded-lg text-indigo-600">
                           <TagIcon className="w-4 h-4" />
                       </div>
                       <span className="text-sm font-semibold text-gray-700">Batch Add Tag:</span>
                  </div>

                  <div className="flex-1 flex items-center gap-2 min-w-[300px]">
                      <input 
                          type="text" 
                          placeholder="Tag (English)" 
                          value={batchTagEn}
                          onChange={(e) => setBatchTagEn(e.target.value)}
                          onKeyDown={(e) => e.key === 'Enter' && handleBatchAddTag()}
                          className="flex-1 text-sm border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                      <input 
                          type="text" 
                          placeholder="中文翻译 (Optional)" 
                          value={batchTagZh}
                          onChange={(e) => setBatchTagZh(e.target.value)}
                          onKeyDown={(e) => e.key === 'Enter' && handleBatchAddTag()}
                          className="flex-1 text-sm border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-indigo-500 outline-none bg-gray-50"
                      />
                      <button
                          onClick={handleBatchAddTag}
                          disabled={!batchTagEn.trim()}
                          className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed flex items-center gap-1 shrink-0"
                      >
                          <Plus className="w-4 h-4" /> Add to All
                      </button>
                  </div>
              </div>

              {/* Status & Main Actions Row */}
              <div className="flex flex-wrap gap-4 items-center justify-between">
                <div className="flex items-center gap-4 text-sm text-gray-600">
                  <span className="font-semibold text-gray-900">Queue Status:</span>
                  <span>Total: {stats.total}</span>
                  <span className="text-green-600">Done: {stats.processed}</span>
                  <span className="text-orange-500">Pending: {stats.pending}</span>
                  {stats.errors > 0 && <span className="text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3"/> Errors: {stats.errors}</span>}
                </div>

                <div className="flex items-center gap-3">
                   <button
                    onClick={clearAll}
                    disabled={isProcessing}
                    className="px-4 py-2 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 disabled:opacity-50"
                  >
                    <Trash className="w-4 h-4" /> Clear
                  </button>

                  <button
                    onClick={processQueue}
                    disabled={isProcessing || stats.pending + stats.errors === 0}
                    className={`
                      px-5 py-2 rounded-lg text-white font-medium shadow-sm transition-all flex items-center gap-2
                      ${isProcessing 
                        ? 'bg-gray-400 cursor-not-allowed' 
                        : (stats.pending + stats.errors === 0 ? 'bg-gray-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-md')
                      }
                    `}
                  >
                    <Play className={`w-4 h-4 ${isProcessing ? 'animate-pulse' : 'fill-current'}`} />
                    {isProcessing ? 'Processing...' : 'Start Labeling'}
                  </button>

                  <button
                    onClick={handleDownloadZip}
                    disabled={isZipping || images.length === 0}
                    className="px-5 py-2 bg-gray-900 text-white rounded-lg font-medium hover:bg-gray-800 hover:shadow-md transition-all flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                     {isZipping ? (
                       <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                     ) : (
                       <Download className="w-4 h-4" />
                     )}
                     Download All
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Image Grid */}
        {images.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {images.map(img => (
              <div key={img.id} className="h-[420px]">
                <ImageCard 
                  item={img} 
                  onRemove={removeImage} 
                  onUpdateTags={updateTags}
                  onRetry={() => {
                    // Reset status to idle so the queue picks it up
                    setImages(prev => prev.map(i => i.id === img.id ? { ...i, status: 'idle', error: undefined } : i));
                  }}
                />
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-20 opacity-50">
            <p className="text-gray-400">No images added yet.</p>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { TagResponse } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-2.5-flash"; // Excellent for vision tasks and speed/cost balance

/**
 * Converts a File object to a Base64 string required by the API.
 */
const fileToPart = (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve({
        inlineData: {
          data: base64String,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates tags for a single image using Gemini.
 */
export const generateImageTags = async (file: File): Promise<TagResponse> => {
  try {
    const imagePart = await fileToPart(file);

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          imagePart,
          {
            text: `Analyze this image in detail. Instead of single keywords, generate **short natural language phrases**.

            **Strictly follow this order for the tags**:
            1. **Character/Identity**: Start with who or what is the subject (e.g., 'a young cyberpunk warrior', 'a cute cat').
            2. **Action/Pose**: Follow with what they are doing or their pose (e.g., 'standing confidently with sword', 'sleeping on a rug').
            3. **Details**: End with clothing, props, background, and perspective (e.g., 'wearing red armor', 'holding a glowing lantern', 'rainy neon street background', 'close-up shot').

            Ensure the translation (zh) is also a natural short phrase, not just a dictionary definition.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tags: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  en: { type: Type.STRING, description: "The tag phrase in English" },
                  zh: { type: Type.STRING, description: "The tag phrase in Chinese" }
                },
                required: ["en", "zh"]
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("No response from AI");
    }

    return JSON.parse(text) as TagResponse;
  } catch (error) {
    console.error("Error generating tags:", error);
    throw error;
  }
};
